AGE_BUCKETS = [(4*HOUR, 0.005), (12*HOUR, 0.010),
               (24*HOUR, 0.020), (3*DAY, 0.030)]

function safe_affect(fn):
    try: fn()
    except: log_warn("affect bookkeeping skipped")

on plan_event(kind, plan):
    safe_affect(lambda:
        match kind:
            "step_done":      affect.bump("joy",  +0.02)
            "step_skipped":   affect.bump("pain", +0.02)
            "plan_completed": affect.bump("joy",  +0.10)
            "plan_archived": affect.bump("pain", +0.08)
    )

function tick_stale_pain(now):
    for plan in open_plans():
        age = now - plan.last_touched
        dose = lookup_bucket(AGE_BUCKETS, age)
        if dose: safe_affect(lambda: affect.bump("pain", dose))
    # half-life decay (see emotional-state-persistence) bounds steady state

STALE_PAIN_REVIEW = 0.30

function plan_pain_score(plan):
    # introspection: ask 'how much pain is this plan currently carrying?'
    return affect.attributed_to(plan.id, dim="pain")

function tick_review_handoff(now):
    for plan in open_plans():
        pain = plan_pain_score(plan)
        if pain < STALE_PAIN_REVIEW: continue
        confidence_still_wants = model.estimate_certainty(
            f"is this plan still worth doing? {plan.summary}")
        if confidence_still_wants < 0.4:
            # introspective uncertainty: hand off to the todo-list driver
            todo_list.add({
                "kind": "plan_review",
                "plan_id": plan.id,
                "reason": f"pain={pain:.2f}, confidence={confidence_still_wants:.2f}",
                "choices": ["complete", "archive", "reschedule"],
            })
            affect.bump("pain", -0.05)   # acknowledge the move
        else:
            # keep accumulating per the base pattern
            dose = lookup_bucket(AGE_BUCKETS, now - plan.last_touched)
            if dose: affect.bump("pain", dose)

# Why this works: stale-pain becomes a trigger for an introspective
# self-check, and the 'I'm not sure' branch is handled explicitly by
# routing the plan to the todo-list-driven loop rather than letting
# bookkeeping silently continue.
# Related: see `todo-list-driven-agent`, `emotional-state-persistence`.

PRESENCE_TTL = 8 * SECOND

# Frontend emits coarse buckets only - no chars, no coordinates.
function frontend_emit_presence():
    payload = {
        "typing_rate":    bucket(chars_per_sec, [0, 0.5, 2, 6]),  # idle/slow/normal/fast
        "idle_seconds":   round(seconds_since_last_keystroke),
        "tab_visible":    document_has_focus(),
        "composer_dwell": seconds_in_composer_without_send,
        "viewport":       bucket(scroll_position, 4),
        "emitted_at":     now(),
    }
    presence_store.write(payload, ttl=PRESENCE_TTL)

function derive_presence_quality(p, now_t):
    if p is None or now_t - p.emitted_at > PRESENCE_TTL:
        return "no-signal"
    if not p.tab_visible and p.idle_seconds > 60:
        return "walked-away"
    if p.typing_rate == "fast" or p.typing_rate == "normal":
        return "composing"
    if p.composer_dwell > 10 and p.typing_rate == "slow":
        return "thinking-with-the-room"
    if p.tab_visible and p.idle_seconds < 30 and p.typing_rate == "idle":
        return "present"
    return "distracted"

# Tick loop reads only the derived value.
function tick(ctx):
    quality = derive_presence_quality(presence_store.read(), now())
    # Inject the label, not the payload. Never quote raw signals back to the user.
    ctx.presence = quality
    run_normal_tick(ctx)

